  "gmat": {
    id: "gmat", title: "GMAT (Graduate Management Admission Test)",
    description: "Practice GMAT questions covering Quantitative Reasoning, Verbal Reasoning, and Data Insights.",
    category: "academic",
    questions: [
      { q: "[Quant] Train A departs at 9:00 AM at 60 mph. Train B departs at 10:00 AM in the same direction at 90 mph. At what time does Train B catch Train A?",
        options: ["11:00 AM", "12:00 PM", "1:00 PM", "2:00 PM"],
        answer: 1,
        explanation: "By 10 AM, Train A has traveled 60 miles. Gap = 60 miles. Closing speed = 90 − 60 = 30 mph. Time to close = 60 ÷ 30 = 2 hours after 10 AM = 12:00 PM." },
      { q: "[Verbal — CR] 'All high performers get bonuses. Maria got a bonus.' What can we conclude?",
        options: ["Maria is a high performer", "Maria may or may not be a high performer", "Maria will get a bonus next year", "Non-high performers never get bonuses"],
        answer: 1,
        explanation: "The premise is 'all high performers get bonuses,' not 'only high performers get bonuses.' Other people may also get bonuses. This is the affirming the consequent fallacy." },
      { q: "[Quant] What is the sum of all integers from 1 to 100?",
        options: ["4,950", "5,000", "5,050", "5,100"],
        answer: 2,
        explanation: "Sum = n(n+1)/2 = 100(101)/2 = 5,050. Gauss's formula: pair first and last terms (1+100, 2+99…) each summing to 101, with 50 pairs." },
      { q: "[Verbal — SC] Choose the most grammatically correct version: 'Neither the manager nor the employees _____ happy.'",
        options: ["was", "are", "is", "were"],
        answer: 1,
        explanation: "With 'neither/nor,' the verb agrees with the noun closest to it. 'Employees' is plural → 'are.' If it were 'nor the manager,' you'd use 'is.'" },
      { q: "[Data Insights] Is x > 0? (1) x² > 0. (2) x > −1. Which statements are sufficient?",
        options: ["Statement 1 alone", "Statement 2 alone", "Both together", "Neither alone nor together"],
        answer: 3,
        explanation: "(1): x² > 0 means x ≠ 0, but x could be negative. Not sufficient. (2): x > −1 includes x = −0.5 (negative) or x = 2 (positive). Not sufficient. Together still insufficient — x = −0.5 or x = 2 both satisfy both conditions." }
    ]
  },

