  "ap-chemistry": {
    id: "ap-chemistry", title: "AP Chemistry",
    description: "Practice for the AP Chemistry exam. Covers atomic structure, bonding, kinetics, equilibrium, and thermodynamics.",
    category: "academic",
    questions: [
      { q: "What is Le Chatelier's Principle?",
        options: ["Reactions always proceed to completion", "A system at equilibrium shifts to counteract any imposed change", "Entropy always increases in a closed system", "Activation energy is independent of temperature"],
        answer: 1,
        explanation: "Le Chatelier's Principle: if a stress (change in concentration, pressure, or temperature) is applied to a system at equilibrium, the system shifts to partially relieve that stress." },
      { q: "What is molarity?",
        options: ["Grams of solute per liter of solution", "Moles of solute per kilogram of solvent", "Moles of solute per liter of solution", "Volume of solute per volume of solution"],
        answer: 2,
        explanation: "Molarity (M) = moles of solute / liters of solution. Molality uses kg of solvent. Molarity is the most common concentration unit in chemistry." },
      { q: "Which type of chemical bond involves the sharing of electron pairs between atoms?",
        options: ["Ionic bond", "Metallic bond", "Hydrogen bond", "Covalent bond"],
        answer: 3,
        explanation: "Covalent bonds share electrons between atoms. Ionic bonds involve electron transfer (forming ions). Metallic bonds involve a sea of delocalized electrons. Hydrogen bonds are intermolecular." },
      { q: "What is the pH of a neutral aqueous solution at 25°C?",
        options: ["0", "7", "10", "14"],
        answer: 1,
        explanation: "At 25°C, [H⁺] = [OH⁻] = 10⁻⁷ M, giving pH = −log(10⁻⁷) = 7. pH < 7 is acidic; pH > 7 is basic. pH 7 is only neutral at 25°C — this changes with temperature." },
      { q: "In a galvanic (voltaic) cell, oxidation occurs at which electrode?",
        options: ["Cathode", "Anode", "Both electrodes equally", "Neither — oxidation occurs in solution"],
        answer: 1,
        explanation: "Mnemonic: 'An Ox, Red Cat' — ANode = OXidation; CAThode = REDuction. In a galvanic cell, the anode is the negative electrode where electrons are produced." }
    ]
  },

