  "bank-po": {
    id: "bank-po", title: "Indian Bank PO Exam (IBPS/SBI PO)",
    description: "Practice for the IBPS PO / SBI PO Prelims. Covers quantitative aptitude, reasoning, English, and banking awareness.",
    category: "government",
    questions: [
      { q: "What does NEFT stand for in Indian banking?",
        options: ["National Electronic Financial Transfer", "National Electronic Funds Transfer", "National Efficient Fund Transfer", "None of the above"],
        answer: 1,
        explanation: "NEFT (National Electronic Funds Transfer) is an RBI-operated system for transferring funds between bank accounts across India. It operates in half-hourly batches and is now available 24/7." },
      { q: "The 'Repo Rate' is the rate at which:",
        options: ["Commercial banks lend to each other overnight", "The RBI lends short-term funds to commercial banks", "The government borrows from the RBI", "Foreign banks can borrow from Indian banks"],
        answer: 1,
        explanation: "The Repo Rate is the rate at which the RBI provides short-term liquidity to commercial banks against government securities. A higher repo rate increases borrowing costs throughout the economy." },
      { q: "What does KYC stand for in the context of Indian banking?",
        options: ["Keep Your Credit", "Know Your Customer", "Key Yield Certificate", "Know Your Credentials"],
        answer: 1,
        explanation: "KYC (Know Your Customer) is a mandatory RBI process for banks to verify the identity and address of customers. Required for opening accounts, large transactions, and preventing money laundering." },
      { q: "What is a Non-Performing Asset (NPA)?",
        options: ["An asset that has depreciated significantly in value", "A loan or advance where interest or principal is overdue for 90+ days", "A bank branch that is not generating profit", "Equity shares that have not paid dividends"],
        answer: 1,
        explanation: "An NPA is a loan where the borrower has not made interest or principal payments for 90 days or more. High NPAs signal credit quality problems and reduce bank profitability." },
      { q: "RTGS (Real Time Gross Settlement) is typically used for:",
        options: ["Small-value retail transactions under ₹2 lakh", "Large-value transactions (minimum ₹2 lakh), settled in real time individually", "Cross-border currency transfers only", "Credit card payment settlements"],
        answer: 1,
        explanation: "RTGS settles transactions individually and in real time (no batching), making it ideal for high-value transfers. Minimum: ₹2 lakh. NEFT is for smaller amounts and settles in batches." }
    ]
  },

  "police-firefighter": {
    id: "police-firefighter", title: "Police / Firefighter Entrance Exam",
    description: "Practice for general law enforcement and fire service entrance exams. Covers reading comprehension, judgment, reasoning, and emergency procedures.",
    category: "government",
    questions: [
      { q: "In law enforcement, 'probable cause' means:",
        options: ["An officer's personal suspicion without any evidence", "Reasonable grounds to believe a crime has been or is being committed, based on specific articulable facts", "A warrant signed by a judge", "Absolute certainty that a crime occurred"],
        answer: 1,
        explanation: "Probable cause is the legal standard for arrests and searches without a warrant. It requires specific facts that would lead a reasonable person to believe a crime was committed — more than suspicion, less than certainty." },
      { q: "What is 'triage' in emergency medical response?",
        options: ["Transporting all patients to the nearest hospital simultaneously", "Sorting and prioritizing patients by severity of injury to maximize overall survival", "Treating patients in the order they were discovered", "Providing equal treatment time to all victims regardless of condition"],
        answer: 1,
        explanation: "Triage (from French 'to sort') prioritizes patients based on urgency and likelihood of survival with treatment. START triage: Immediate (life-threatening, treatable) → Delayed → Minor → Expectant (survivability unlikely)." },
      { q: "The 'chain of custody' for evidence is important because:",
        options: ["It speeds up the prosecution process", "It documents every person who handled the evidence, ensuring it was not tampered with and maintaining its admissibility in court", "It determines the value of the evidence for insurance purposes", "It allows defense attorneys to review evidence in advance"],
        answer: 1,
        explanation: "Chain of custody documentation tracks who collected, handled, transferred, and stored evidence. A broken chain can render evidence inadmissible in court, potentially compromising a prosecution." },
      { q: "When arriving at a vehicle accident scene, what is the first priority?",
        options: ["Remove injured persons from vehicles immediately", "Ensure your own safety and the scene is safe before approaching", "Determine who was at fault", "Begin CPR on the most seriously injured person"],
        answer: 1,
        explanation: "First responder safety is paramount. Assess for traffic hazards, fire, downed power lines, and other risks before approaching victims. An incapacitated first responder becomes another victim." },
      { q: "Under the Americans with Disabilities Act (ADA), public safety agencies must:",
        options: ["Hire applicants with disabilities regardless of ability to perform essential job functions", "Provide reasonable accommodations to qualified individuals with disabilities unless doing so causes undue hardship", "Exempt all physical fitness requirements for applicants with disabilities", "Maintain separate hiring pools for disabled applicants"],
        answer: 1,
        explanation: "The ADA requires reasonable accommodation for qualified individuals with disabilities who can perform the essential functions of the job. Agencies may still enforce genuine, job-related physical standards (e.g., ability to carry required equipment)." }
    ]
  },

